package com.example;

import org.springframework.beans.factory.annotation.Value;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.oauth2.client.registration.ClientRegistration;
import org.springframework.security.oauth2.client.registration.ClientRegistrationRepository;
import org.springframework.security.oauth2.client.web.OAuth2AuthorizedClientRepository;
import org.springframework.security.oauth2.client.web.reactive.function.client.ServletOAuth2AuthorizedClientExchangeFilterFunction;
import org.springframework.security.web.SecurityFilterChain;
import org.springframework.web.client.RestTemplate;

@Configuration
public class SecurityConfig {

    @Value("${oauth2-client.client-id}")
    private String clientId;

    @Value("${oauth2-client.redirect-uri}")
    private String redirectUri;

    @Value("${oauth2-client.scope}")
    private String scope;

    @Value("${oauth2-client.response-type}")
    private String responseType = "code";

    private final ClientRegistrationRepository clientRegistrationRepository;
    private final RestTemplate restTemplate = new RestTemplate();
    private final OAuth2AuthorizedClientRepository oAuth2AuthorizedClientRepository;

    public SecurityConfig(ClientRegistrationRepository clientRegistrationRepository,
                           OAuth2AuthorizedClientRepository oAuth2AuthorizedClientRepository) {
        this.clientRegistrationRepository = clientRegistrationRepository;
        this.oAuth2AuthorizedClientRepository = oAuth2AuthorizedClientRepository;
    }

    public SecurityFilterChain filterChain(HttpSecurity http) throws Exception {
        ClientRegistration clientRegistration = clientRegistrationRepository.findByRegistrationId(clientId);
        ServletOAuth2AuthorizedClientExchangeFilterFunction oauth2 =
                new ServletOAuth2AuthorizedClientExchangeFilterFunction(clientRegistration, oAuth2AuthorizedClientRepository);
        http
                .authorizeRequests()
                    .anyRequest().authenticated()
                .and()
                .oauth2Login()
                    .and()
                .oauth2Client(client -> client
                        .registerClient(clientRegistration)
                        .filterAfter(oauth2));

        return http.build();
    }
}